import numpy as np
import os
import sys
try:
    from psychopy import core, visual
except ImportError:
    print("Psychopy not downloaded.")

base_dir = os.path.dirname(os.path.abspath(__file__))
sys.path.append(os.path.join(base_dir, "..", ".."))

from experiment.triggers import get_trigger_sender, TriggerCode

temp_trigger = get_trigger_sender()

class MainExpInterface:
    def __init__(self, fullscr=False):
        self.b_col = "#141E36"
        if fullscr:
            self.win = visual.Window(fullscr=True, color=self.b_col, units="norm")
            self.win_width, self.win_height = self.win.size
        else:
            self.win_width, self.win_height = 800, 600 # Mid-screen = 0,0, x_left = -1
            self.win = visual.Window(size=[self.win_width, self.win_height], fullscr=False, color=self.b_col, units="norm")

        self.fixation_cross = visual.TextStim(text="+", win=self.win, color="white", height=0.2)

        self.default_color = "#3a3f43"

    def fix_cross(self, duration=10.0):
        self.fixation_cross.draw()
        self.notifications_box.draw()
        self.win.flip()
        core.wait(duration)

    def portfolio_display(self, init_value, value, margins, position):
        left_x = margins["left"]+0.3
        right_x = margins["right"] - 0.3
        text_offset_y = margins["bottom"]-0.2
        num_offset_y = margins["bottom"]-0.3

        if value > round(init_value, 2):
                num_color = "green"
        elif value < round(init_value, 2):
                num_color = "red"
        else:
                num_color = self.default_color 

        if position == "invested":
            description_invested = visual.TextStim(win=self.win, text="Your Investment Value:", 
                                            pos=(left_x, text_offset_y), color="#FFFFFF")

            portfolio = visual.TextStim(win=self.win, text=str(round(value, 2)), 
                                            pos=(left_x, num_offset_y), color=num_color)
            
            cash_description = visual.TextStim(win=self.win, text="What if: Cash Value", 
                                   pos=(right_x, text_offset_y), color="#FFFFFF")
            
            cash = visual.TextStim(win=self.win, text=str(init_value), 
                                   pos=(right_x, num_offset_y), color=self.default_color)
            
        else:
            cash_description = visual.TextStim(win=self.win, text="Your Cash Value", 
                                   pos=(left_x, text_offset_y), color="#FFFFFF")
            
            cash = visual.TextStim(win=self.win, text=str(init_value), 
                                   pos=(left_x, num_offset_y), color=self.default_color)
            
            description_invested = visual.TextStim(win=self.win, text="What if: Investment Value", 
                                            pos=(right_x, text_offset_y), color="#FFFFFF")
            
            portfolio = visual.TextStim(win=self.win, text=str(round(value, 2)), 
                                            pos=(right_x, num_offset_y), color=num_color)
            
        return description_invested, portfolio, cash_description, cash
    
    def build_chart(self, values, position, jump, jump_point, trigger):
        # Chart Margins
        margins = {
            "left": -1 + 2*0.1,
            "right": -1 + 2*0.9,
            "bottom": -1 + 2*0.3,
            "up": -1 + 2*0.9
        }

        # X-coordinates and Y-coordinates
        baseline = values[0]
        bottom_y, top_y = (baseline*0.85, baseline*1.15)

        ys = np.interp(values, (bottom_y, top_y), (margins["bottom"], margins["up"]))
        y_mid_px = np.interp(baseline, (bottom_y, top_y), (margins["bottom"], margins["up"]))

        xs = np.linspace(margins["left"], margins["right"], len(values))
        ys = np.interp(values, (bottom_y, top_y), (margins["bottom"], margins["up"]))
        vertices = list(zip(xs, ys))

        # Color lines & draw
        axis_colors = self.default_color

        x_axis = visual.Line(self.win, start=(margins["left"], margins["bottom"]), end=(margins["right"], margins["bottom"]),
                     lineColor=axis_colors, lineWidth=4)
        
        y_axis = visual.Line(self.win, start=(margins["left"], margins["bottom"]), end=(margins["left"], margins["up"]),
                     lineColor=axis_colors, lineWidth=4)

        price_line = visual.ShapeStim(self.win, vertices=vertices[:2], closeShape=False,
                        lineColor="#2196f3", fillColor=None, lineWidth=3)

        midline = visual.Line(self.win, 
                      start=(margins["left"], y_mid_px), 
                      end=(margins["right"], y_mid_px),
                      lineColor="#6a7482", 
                      lineWidth=1)
        
        y_top_text = visual.TextStim(win=self.win, text=str(int(round(top_y, 0))), 
                                     pos=(margins["left"]-0.05, margins["up"]), height=0.05, color=axis_colors)
        
        y_bottom_text = visual.TextStim(win=self.win, text=str(int(round(bottom_y, 0))), 
                                     pos=(margins["left"]-0.05, margins["bottom"]), height=0.05, color=axis_colors)
        
        for i in range(2, len(values)+1):
            price_line.vertices = vertices[:i]
            x_axis.draw()
            y_axis.draw()
            y_top_text.draw()
            y_bottom_text.draw()
            midline.draw()
            price_line.draw()
            description_invested, portfolio, cash_description, cash = self.portfolio_display(values[0], values[i-1], margins, position)
            description_invested.draw()
            portfolio.draw()
            cash_description.draw()
            cash.draw()
            if i == jump_point:
                if jump > 0:
                    trigger.send(TriggerCode.SPIKE_POSITIVE)
                else:
                    trigger.send(TriggerCode.SPIKE_NEGATIVE) 
            self.win.flip()
            core.wait(0.01)
            
        core.wait(10.0)

